:root {
  --bg-terminal: #0d0d0d;
  --bg-header: #1a1a1a;
  --bg-track: #1e1e1e;
  --color-text: #c8ffc8;
  --color-dim: #5a8a5a;
  --color-title: #a0e0a0;
  --color-high: #ff5f5f;
  --color-mid: #f0c040;
  --color-low: #50e080;
  --color-dot-red: #ff5f5f;
  --color-dot-yellow: #f0c040;
  --color-dot-green: #50e080;
  --color-divider: #2a3a2a;
  --color-prompt: #50e080;
  --color-log: #6aaa6a;
  --color-info-label: #5a8a5a;
  --color-info-value: #c8ffc8;
}

.terminal {
  width: 520px;
  background-color: var(--bg-terminal);
  border-radius: 8px;
  border: 1px solid var(--color-divider);
  overflow: hidden;
  margin: 0 auto;
}

.terminal-header {
  background-color: var(--bg-header);
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-bottom: 1px solid var(--color-divider);
}

.header-dots {
  display: flex;
  align-items: center;
  gap: 6px;
}

.dot {
  display: block;
  width: 11px;
  height: 11px;
  border-radius: 50%;
}

.dot-red { background-color: var(--color-dot-red); }
.dot-yellow { background-color: var(--color-dot-yellow); }
.dot-green { background-color: var(--color-dot-green); }

.terminal-title {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: var(--color-title);
  flex: 1;
  text-align: center;
}

.terminal-body {
  padding: 16px 18px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.status-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.label {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: var(--color-dim);
  width: 72px;
  flex-shrink: 0;
}

.bar-track {
  flex: 1;
  height: 10px;
  background-color: var(--bg-track);
  border-radius: 2px;
  border: 1px solid var(--color-divider);
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 2px;
}

.bar-high { width: 87%; background-color: var(--color-high); }
.bar-mid  { width: 54%; background-color: var(--color-mid); }
.bar-low  { width: 23%; background-color: var(--color-low); }

.value {
  font-size: 12px;
  font-weight: 700;
  width: 36px;
  text-align: right;
  flex-shrink: 0;
}

.val-high { color: var(--color-high); }
.val-mid  { color: var(--color-mid); }
.val-low  { color: var(--color-low); }

.divider {
  height: 1px;
  background-color: var(--color-divider);
  margin: 2px 0;
}

.info-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.info-cell {
  display: flex;
  flex-direction: column;
  gap: 3px;
  background-color: var(--bg-header);
  border: 1px solid var(--color-divider);
  border-radius: 4px;
  padding: 8px 10px;
}

.info-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.1em;
  color: var(--color-info-label);
}

.info-value {
  font-size: 14px;
  font-weight: 700;
  color: var(--color-info-value);
}

.log-line {
  font-size: 11px;
  color: var(--color-log);
  letter-spacing: 0.04em;
  line-height: 1.5;
}

.prompt {
  color: var(--color-prompt);
  margin-right: 6px;
  font-weight: 700;
}
